import { config, setShippingMethods } from '@/checkout/api';
import {
  ShippingMethodItemSlot,
  ShippingMethods as ShippingMethodsComponent,
} from '@/checkout/components/ShippingMethods';
import {
  Cart,
  NegotiableQuote,
  ShippingEstimate,
  ShippingMethod,
  ShippingMethodInput,
} from '@/checkout/data/models';
import { transformShippingEstimateShippingMethod } from '@/checkout/data/transforms';
import {
  getLatestCheckoutUpdate,
  getValue,
  hasPendingShippingEstimate,
  hasPendingUpdates,
  hasShippingAddress,
  isQuoteCheckout,
  notifyValues,
} from '@/checkout/lib';
import { Filter, TitleProps, UIComponentType } from '@/checkout/types';
import { useText } from '@adobe-commerce/elsie/i18n';
import { Container, Slot } from '@adobe-commerce/elsie/lib';
import { events } from '@adobe-commerce/event-bus';
import { HTMLAttributes } from 'preact/compat';
import {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'preact/hooks';

/**
 * Context provided to the ShippingMethodItem slot.
 * Used for complete UI replacement via replaceWith.
 */
export interface ShippingMethodItemContext {
  method: ShippingMethod;
  isSelected: boolean;
  onSelect: () => void;
}

interface CartSyncError {
  method: ShippingMethod;
  error: Error;
}

export type ShippingOptionsFilter = Filter<ShippingMethod>;

export interface ShippingMethodsProps
  extends HTMLAttributes<HTMLDivElement>,
    TitleProps {
  UIComponentType?: UIComponentType;
  active?: boolean;
  autoSync?: boolean;
  onCartSyncError?: (error: CartSyncError) => void;
  onSelectionChange?: (method: ShippingMethod) => void;
  slots?: {
    ShippingMethodItem?: ShippingMethodItemSlot;
  } & TitleProps['slots'];
}

function isMethodAvailable(
  method: ShippingMethod | null,
  options: ShippingMethod[]
) {
  if (!method) return false;
  return options.some((option) => isEqual(option, method));
}

function isEqual(a: ShippingMethod | null, b: ShippingMethod | null) {
  if (!a || !b) return false;
  if (a.amount.value !== b.amount.value) return false;
  return a.code === b.code && a.carrier.code === b.carrier.code;
}

export function emitShippingEstimateEvent(selection: ShippingMethod) {
  const shippingEstimatedEvent = events.lastPayload('shipping/estimate');

  if (!shippingEstimatedEvent) return;

  events.emit('shipping/estimate', {
    ...shippingEstimatedEvent,
    shippingMethod: transformShippingEstimateShippingMethod(selection),
  });
}

export const ShippingMethods: Container<ShippingMethodsProps> = ({
  UIComponentType = 'RadioButton',
  active = true,
  autoSync = true,
  displayTitle = true,
  initialData,
  slots,
  onCartSyncError,
  onSelectionChange,
  ...props
}) => {
  const [error, setError] = useState<string | null>(null);
  const [isVirtual, setIsVirtual] = useState(false);
  const [options, setOptions] = useState<ShippingMethod[] | undefined>();
  const [selection, setSelection] = useState<ShippingMethod | null>(null);
  const initialQuoteOptions = useRef<ShippingMethod[] | null>(null);

  const hasQueuedUpdates = hasPendingUpdates.value;
  const hasPendingEstimations = hasPendingShippingEstimate.value;

  const { cartSyncError, defaultTitle } = useText({
    cartSyncError: 'Checkout.ShippingMethods.cartSyncError',
    defaultTitle: 'Checkout.ShippingMethods.title',
  });

  const filterOptions = useCallback(
    (shippingMethods: ShippingMethod[] | undefined) => {
      if (!shippingMethods || shippingMethods.length === 0) return [];
      const { shipping } = config.getConfig();
      if (!shipping?.filterOptions) return shippingMethods;
      return shippingMethods.filter(shipping.filterOptions);
    },
    []
  );

  const preselectOption = useCallback((shippingMethods: ShippingMethod[]) => {
    if (shippingMethods.length === 0) return null;
    const { defaults } = config.getConfig();
    return defaults!.selectedShippingMethod!(shippingMethods);
  }, []);

  const filteredOptions = useMemo(() => {
    return filterOptions(options);
  }, [options, filterOptions]);

  const handleDismissError = useCallback(() => {
    setError(null);
  }, []);

  const setUserSelection = useCallback(
    (shippingMethod: ShippingMethod | null) => {
      setError(null);
      setSelection((prev) => {
        if (isEqual(prev, shippingMethod)) return prev;
        notifyValues({ selectedShippingMethod: shippingMethod });
        return shippingMethod;
      });
    },
    []
  );

  const setUserSelectionOnCart = useCallback(
    async (selection: ShippingMethod, fallback?: ShippingMethod | null) => {
      if (!autoSync || !hasShippingAddress()) return;

      const shippingMethodInput: ShippingMethodInput = {
        carrierCode: selection.carrier.code,
        methodCode: selection.code,
      };

      setShippingMethods([shippingMethodInput]).catch((error) => {
        setUserSelection(fallback ?? null);
        onCartSyncError?.({ method: selection, error });

        if (!onCartSyncError) {
          setError(cartSyncError);
        }
      });
    },
    [autoSync, setUserSelection, onCartSyncError, cartSyncError]
  );

  const handleSelectionChange = useCallback(
    async (selection: ShippingMethod) => {
      const prevSelection = getValue('selectedShippingMethod');

      setUserSelection(selection);
      onSelectionChange?.(selection);

      if (!hasShippingAddress()) {
        emitShippingEstimateEvent(selection);
      }

      await setUserSelectionOnCart(selection, prevSelection);
    },
    [onSelectionChange, setUserSelection, setUserSelectionOnCart]
  );

  const handleCheckoutData = useCallback(
    (data: Cart | NegotiableQuote | null) => {
      const isEmptyCart = !data || data.isEmpty;
      const isVirtualCart = Boolean(data?.isVirtual);

      if (isEmptyCart || isVirtualCart) {
        setIsVirtual(isVirtualCart);
        setUserSelection(null);
        setOptions([]);
        return;
      }

      const primaryAddress = data!.shippingAddresses?.[0];

      // If there is no primary address, options are handled by the shipping estimation
      if (!primaryAddress) return;

      const availableOptions = primaryAddress.availableShippingMethods ?? [];

      // For quote checkouts, preserve initial shipping methods. After the first method is selected,
      // the backend only returns that selected method, preventing users from changing to other
      // options. We maintain all initial options to match Luma's behavior.
      if (isQuoteCheckout() && !initialQuoteOptions.current) {
        initialQuoteOptions.current = availableOptions;
      }

      const effectiveOptions =
        isQuoteCheckout() && initialQuoteOptions.current
          ? initialQuoteOptions.current
          : availableOptions;

      setOptions(effectiveOptions);
      const filteredOptions = filterOptions(effectiveOptions);

      // If there are no filtered options, reset the user selection
      if (filteredOptions.length === 0) {
        setUserSelection(null);
        return;
      }

      const cartSelection = primaryAddress.selectedShippingMethod ?? null;

      const userSelection = getValue('selectedShippingMethod');
      const isAvailable = isMethodAvailable(userSelection, filteredOptions);
      const haveSameSelection = isEqual(userSelection, cartSelection);

      // Handle user selection that's available but different from cart
      if (userSelection && isAvailable && !haveSameSelection) {
        setUserSelectionOnCart(userSelection, cartSelection);
        return;
      }

      // If no user selection or not available, decide what to do based on cart and filtered options
      if ((!userSelection || !isAvailable) && cartSelection) {
        // Check if cart selection is still available after filtering
        const isCartSelectionAvailable = isMethodAvailable(
          cartSelection,
          filteredOptions
        );
        if (isCartSelectionAvailable) {
          setUserSelection(cartSelection);
          return;
        }
      }

      if (
        (!userSelection || !isAvailable) &&
        (!cartSelection || !isMethodAvailable(cartSelection, filteredOptions))
      ) {
        const newSelection = preselectOption(filteredOptions);
        setUserSelection(newSelection);
        if (newSelection) setUserSelectionOnCart(newSelection);
      }
    },
    [filterOptions, preselectOption, setUserSelection, setUserSelectionOnCart]
  );

  const handleShippingEstimate = useCallback(
    (estimation: ShippingEstimate | undefined) => {
      if (estimation === undefined) return;

      const { shippingMethod, availableShippingMethods } = estimation;

      const selectedShippingMethod =
        availableShippingMethods?.find(
          (method) =>
            method.code === shippingMethod?.methodCode &&
            method.carrier.code === shippingMethod?.carrierCode
        ) ?? null;

      setOptions(availableShippingMethods);
      setUserSelection(selectedShippingMethod);
    },
    [setUserSelection]
  );

  useEffect(() => {
    if (!active) return;

    const pastUpdate = getLatestCheckoutUpdate();

    if (pastUpdate) {
      // When component becomes active, restore key state so handleCheckoutData can work properly
      const userSelection = getValue('selectedShippingMethod');
      if (userSelection) {
        setSelection(userSelection);
      }

      handleCheckoutData(pastUpdate);
      return;
    }

    const onCheckoutInit = events.on(
      'checkout/initialized',
      handleCheckoutData,
      { eager: true }
    );

    return () => {
      onCheckoutInit?.off();
    };
  }, [active, handleCheckoutData]);

  useEffect(() => {
    if (!active) return;

    const onCheckoutUpdated = events.on(
      'checkout/updated',
      handleCheckoutData,
      { eager: false }
    );

    return () => {
      onCheckoutUpdated?.off();
    };
  }, [active, handleCheckoutData]);

  useEffect(() => {
    if (!active || hasShippingAddress()) return;

    const onShippingEstimate = events.on(
      'shipping/estimate',
      handleShippingEstimate,
      { eager: true }
    );

    return () => {
      onShippingEstimate?.off();
    };
  }, [active, handleShippingEstimate]);

  const titleContent = useMemo(() => {
    if (!displayTitle) return undefined;

    return (
      <Slot name="checkout-shipping-methods-title" slot={slots?.Title}>
        <h3>{defaultTitle}</h3>
      </Slot>
    );
  }, [displayTitle, slots?.Title, defaultTitle]);

  return (
    <ShippingMethodsComponent
      {...props}
      UIComponentType={UIComponentType}
      busy={hasQueuedUpdates || hasPendingEstimations}
      error={error}
      initialized={options !== undefined}
      options={filteredOptions}
      selection={selection}
      shippingMethodItemSlot={slots?.ShippingMethodItem}
      title={titleContent}
      visible={active && !isVirtual}
      onDismissError={handleDismissError}
      onSelectionChange={handleSelectionChange}
    />
  );
};
